public async UniTask<GameObject> InstantiateAsync(AssetReferenceGameObject reference, Transform parent, CancellationToken token)
{
    if (reference == null || string.IsNullOrWhiteSpace(reference.AssetGUID))
        throw new ArgumentException("[AddressablesUIAssetService] AssetReference cannot be null or empty.", nameof(reference));

    token.ThrowIfCancellationRequested();

    var tcs = new UniTaskCompletionSource<GameObject>();
    var handle = reference.InstantiateAsync(parent, false);

    var load = new QueuedLoad { Handle = handle, Tcs = tcs };

    CancellationTokenRegistration ctr = default;
    if (token.CanBeCanceled)
    {
        ctr = token.Register(() =>
        {
            load.LoadCompleted = true;
            load.Error = new OperationCanceledException(token);
            DrainQueue();
        });
    }

    lock (_lock) { _queue.Enqueue(load); }

    handle.Completed += h =>
    {
        ctr.Dispose();

        if (load.LoadCompleted)
        {
            ReleaseCompleted(h);
            return;
        }

        load.LoadCompleted = true;
        if (h.Status != AsyncOperationStatus.Succeeded || h.Result == null)
        {
            load.Error = h.OperationException ??
                new Exception($"[AddressablesUIAssetService] Failed to instantiate UI prefab: {reference}");
            if (h.IsValid())
                Addressables.Release(h);
        }

        DrainQueue();
    };

    return await tcs.Task;
}

private void DrainQueue()
{
    lock (_lock)
    {
        while (_queue.Count > 0 && _queue.Peek().LoadCompleted)
        {
            var load = _queue.Dequeue();
            if (load.Error != null)
                load.Tcs.TrySetException(load.Error);
            else
                load.Tcs.TrySetResult(load.Handle.Result);
        }
    }
}

public void Release(GameObject instance)
{
    if (instance != null)
        Addressables.ReleaseInstance(instance);
}

private static void ReleaseCompleted(AsyncOperationHandle<GameObject> handle)
{
    if (handle.Status == AsyncOperationStatus.Succeeded && handle.Result != null)
    {
        Addressables.ReleaseInstance(handle.Result);
        return;
    }

    if (handle.IsValid())
        Addressables.Release(handle);
}

public UIModuleContext(UIRuntime runtime, UIWindow window, CancellationToken destroyToken)
{
    Runtime = runtime;
    Window = window;
    DestroyToken = destroyToken;
}

public UIModuleContext CreateChildContext()
{
    return new UIModuleContext(Runtime, Window, DestroyToken);
}

protected void BindFields(Transform root)
{
    UIViewAutoBind.Bind(this, root);
}

protected void BindFields(GameObject root)
{
    if (root != null)
        UIViewAutoBind.Bind(this, root.transform);
}

internal void Attach(UIModuleContext context)
{
    if (context == null)
        throw new ArgumentNullException(nameof(context));

    Context = context;
    _cts = CancellationTokenSource.CreateLinkedTokenSource(context.DestroyToken);
}

internal async UniTask StartAsync()
{
    if (_disposed || _started)
        return;

    _started = true;
    await OnStart();
}

protected virtual UniTask OnStart()
{
    return UniTask.CompletedTask;
}

protected virtual void OnStop()
{
}

protected T AddModule<T>(T module) where T : UIModuleBase
{
    if (module == null)
        throw new ArgumentNullException(nameof(module));

    module.Attach(Context.CreateChildContext());
    _children.Add(module);
    module.StartAsync().Forget();
    return module;
}

protected async UniTask<T> AddModuleAsync<T>(T module) where T : UIModuleBase
{
    if (module == null)
        throw new ArgumentNullException(nameof(module));

    module.Attach(Context.CreateChildContext());
    _children.Add(module);
    await module.StartAsync();
    return module;
}

protected void RegisterChild(UIModuleBase module)
{
    if (module == null)
        throw new ArgumentNullException(nameof(module));

    module.Attach(Context.CreateChildContext());
    _children.Add(module);
}

protected void AddCleanup(Action cleanup)
{
    if (cleanup != null)
        _cleanups.Add(cleanup);
}

protected void RunTask(Func<CancellationToken, UniTask> task)
{
    if (task == null)
        return;

    RunTaskInternal(task).Forget();
}

protected void Delay(float seconds, Action callback)
{
    RunTask(async token =>
    {
        await UniTask.Delay(TimeSpan.FromSeconds(seconds), cancellationToken: token);
        if (!token.IsCancellationRequested)
            callback?.Invoke();
    });
}

protected void Every(float seconds, Func<UniTask> callback, bool immediately = false)
{
    RunTask(async token =>
    {
        if (immediately && callback != null)
            await callback();

        while (!token.IsCancellationRequested)
        {
            await UniTask.Delay(TimeSpan.FromSeconds(seconds), cancellationToken: token);
            if (!token.IsCancellationRequested && callback != null)
                await callback();
        }
    });
}

protected void BindClick(Button button, Action action)
{
    if (button == null)
        return;

    BindClick(button, () => { action?.Invoke(); return UniTask.CompletedTask; });
}

protected void BindClick(Button button, Func<UniTask> asyncAction)
{
    if (button == null)
        return;

    UnityEngine.Events.UnityAction listener = () =>
    {
        if (!DestroyToken.IsCancellationRequested)
            asyncAction?.Invoke().Forget();
    };

    button.onClick.AddListener(listener);
    AddCleanup(() =>
    {
        if (button != null)
            button.onClick.RemoveListener(listener);
    });
}

private async UniTaskVoid RunTaskInternal(Func<CancellationToken, UniTask> task)
{
    try
    {
        await task(DestroyToken);
    }
    catch (OperationCanceledException)
    {
    }
    catch (Exception e)
    {
        Debug.LogException(e);
    }
}

public void Dispose()
{
    if (_disposed)
        return;

    _disposed = true;

    try
    {
        _cts?.Cancel();

        for (int i = _children.Count - 1; i >= 0; i--)
        {
            try
            {
                _children[i]?.Dispose();
            }
            catch (Exception e)
            {
                Debug.LogException(e);
            }
        }
        _children.Clear();

        for (int i = _cleanups.Count - 1; i >= 0; i--)
        {
            try
            {
                _cleanups[i]?.Invoke();
            }
            catch (Exception e)
            {
                Debug.LogException(e);
            }
        }

        _cleanups.Clear();

        try
        {
            OnStop();
        }
        catch (Exception e)
        {
            Debug.LogException(e);
        }
    }
    finally
    {
        _cts?.Dispose();
        _cts = null;
    }
}

