public void RegisterLayer(UILayer layer, Transform root)
{
    if (root == null)
        throw new ArgumentNullException(nameof(root));

    _layerRoots[layer] = root;
}

public Transform GetLayerRoot(UILayer layer)
{
    if (_layerRoots.TryGetValue(layer, out var root))
        return root;

    throw new InvalidOperationException(
        $"[UIRoot] Layer root not registered: {layer}. Add the matching Canvas child or register the layer before opening a view.");
}

private void OnEnable()
{
    Handle();
}

private void OnDestroy()
{
    OnDestroyAction?.Invoke();
}

public override string ToString()
{
    var sb = new StringBuilder();
    sb.AppendLine("<b>UIRootAdapt</b>: ");
    sb.AppendLine("<b>Mode</b>: " + _mode);
    sb.AppendLine("<b>SideVal</b>: " + SideVal);
    sb.AppendLine("<b>ScreenSideVal</b>: " + ScreenSideVal);
    return sb.ToString();
}

// Update is called once per frame
void Update()
{
    if (!Application.isPlaying)
    {
        if (_lastMode != _mode)
        {
            _lastMode = _mode;
            Handle();
        }
    }
}

#endif

    private void Handle()
    {
        switch (_mode)
        {
            case AdaptMode.Expand:
                foreach (var scaler in _scalers)
                {
                    scaler.uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
                    scaler.screenMatchMode = CanvasScaler.ScreenMatchMode.Expand;
                }
                _ImageLeft?.gameObject?.SetActive(false);
                _ImageRight?.gameObject?.SetActive(false);
                SideVal = 0;
                break;
            case AdaptMode.DarkSide:
                var fitHeight = false;
                var canvas0 = _scalers[0].GetComponent<Canvas>();
                var screenSize = canvas0.renderingDisplaySize;
                var referenceResolution = _scalers[0].referenceResolution;
                fitHeight = screenSize.x / referenceResolution.x > screenSize.y / referenceResolution.y;

                foreach (var scaler in _scalers)
                {
                    var canvas = scaler.GetComponent<Canvas>();
                    Debug.Assert(scaler.referenceResolution == referenceResolution);
                    scaler.uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
                    scaler.screenMatchMode = CanvasScaler.ScreenMatchMode.MatchWidthOrHeight;
                    scaler.matchWidthOrHeight = fitHeight ? 1 : 0;
                }

                _ImageLeft?.gameObject.SetActive(fitHeight);
                _ImageRight?.gameObject.SetActive(fitHeight);
                if (fitHeight)
                {
                    var calcScreenSize = referenceResolution.y * screenSize.x / screenSize.y;
                    SideVal = (calcScreenSize - referenceResolution.x) / 2;
                    ScreenSideVal = SideVal * screenSize.x / calcScreenSize;
                    var val = calcScreenSize - SideVal;
                    if (_ImageRight != null)
                    {
                        var offsetMin = _ImageRight.rectTransform.offsetMin;
                        _ImageRight.rectTransform.offsetMin = new Vector2(val, offsetMin.y);
                    }

                    if (_ImageLeft != null)
                    {
                        var offsetMax = _ImageLeft.rectTransform.offsetMax;
                        _ImageLeft.rectTransform.offsetMax = new Vector2(-val, offsetMax.y);
                    }
                }
                else
                {
                    SideVal = 0;
                    ScreenSideVal = 0;
                }
                break;
        }

        foreach (var control in _controlls)
        {
            var offsetMin = control.offsetMin;
            control.offsetMin = new Vector2(SideVal, offsetMin.y);
            var offsetMax = control.offsetMax;
            control.offsetMax = new Vector2(-SideVal, offsetMax.y);
        }

        var screenOffsetPixels = SideVal * Screen.height / _scalers[0].referenceResolution.y;
        var viewOffsetnormalizedDis = screenOffsetPixels / Screen.width;
        ViewPort = new Rect(new Vector2(viewOffsetnormalizedDis, 0), new Vector2(1 - 2 * viewOffsetnormalizedDis, 1));
    }

public UIRuntime(
    UIRoot root,
    IUIAssetService asset,
    UIMaskService mask,
    UIBlurService blur,
    UIInputBlockService inputBlock)
{
    Root = root ?? throw new ArgumentNullException(nameof(root));
    Asset = asset ?? throw new ArgumentNullException(nameof(asset));
    Mask = mask ?? throw new ArgumentNullException(nameof(mask));
    Blur = blur ?? throw new ArgumentNullException(nameof(blur));
    InputBlock = inputBlock ?? throw new ArgumentNullException(nameof(inputBlock));
    Instance = this;
}

public async UniTask<TView> Open<TView>(object param = null) where TView : ViewBase
{
    var viewType = typeof(TView);
    var config = UIViewRegistry.Get(viewType);

    var window = new UIWindow(this, viewType, config, ++_windowIndex);
    window.Attach(new UIModuleContext(this, window, CancellationToken.None));
    _allWindows.Add(window);

    if (config.EnterPopupStack)
        InsertSorted(_popupStack, window);

    try
    {
        await window.OpenAsync(viewType, param);
        return window.View as TView;
    }
    catch
    {
        RemoveWindow(window);
        throw;
    }
}

public void Close<TView>(object result = null) where TView : ViewBase
{
    FindTopWindow(typeof(TView))?.CloseAsync(result).Forget();
}

public TView Get<TView>() where TView : ViewBase
{
    return FindTopWindow(typeof(TView))?.View as TView;
}

public bool IsOpen<TView>() where TView : ViewBase
{
    return FindTopWindow(typeof(TView))?.IsReady == true;
}

public void HandleEsc()
{
    GetTopPopup()?.HandleEsc();
}

internal void RefreshPresentation()
{
    RefreshRenderOrder();
    RefreshCoverState();
    Mask.Refresh();
}

internal void RemoveWindow(UIWindow window)
{
    if (window == null)
        return;

    _allWindows.Remove(window);
    _popupStack.Remove(window);
}

private UIWindow FindTopWindow(Type viewType)
{
    for (var i = _allWindows.Count - 1; i >= 0; i--)
    {
        var window = _allWindows[i];
        if (window != null &&
            window.ViewType == viewType &&
            window.State != UIWindowState.Closed &&
            window.State != UIWindowState.Disposed)
        {
            return window;
        }
    }

    return null;
}

public UIWindow GetTopPopup()
{
    for (var i = _popupStack.Count - 1; i >= 0; i--)
    {
        var win = _popupStack[i];
        if (win != null && win.IsReady)
            return win;
    }

    return null;
}

public void Dispose()
{
    for (var i = _allWindows.Count - 1; i >= 0; i--)
        _allWindows[i]?.Dispose();

    _allWindows.Clear();
    _popupStack.Clear();
    Mask.Dispose();
    Blur.Dispose();
    InputBlock.Dispose();

    if (Instance == this)
        Instance = null;
}

private void RefreshRenderOrder()
{
    foreach (var list in _layerGroups.Values)
        list.Clear();

    foreach (var window in _allWindows)
    {
        if (window == null || window.GameObject == null)
            continue;

        if (!_layerGroups.TryGetValue(window.Config.Layer, out var list))
        {
            list = new List<UIWindow>();
            _layerGroups[window.Config.Layer] = list;
        }

        list.Add(window);
    }

    foreach (var group in _layerGroups.Values)
    {
        group.Sort((a, b) => a.SortOrder.CompareTo(b.SortOrder));

        for (var i = 0; i < group.Count; i++)
        {
            var transform = group[i].GameObject.transform;
            if (transform != null && transform.GetSiblingIndex() != i)
                transform.SetSiblingIndex(i);
        }
    }
}

private void RefreshCoverState()
{
    UIWindow topFullScreen = null;

    for (var i = _popupStack.Count - 1; i >= 0; i--)
    {
        var win = _popupStack[i];
        if (win == null || !win.IsReady)
            continue;

        if (win.Config.FullScreen)
        {
            topFullScreen = win;
            break;
        }
    }

    if (topFullScreen == null)
    {
        SceneMgr.Instance?.SetCurrentSceneCoveredByUI(false);

        foreach (var win in _allWindows)
        {
            if (win != null)
                win.ReShowByCover();
        }
        return;
    }

    SceneMgr.Instance?.SetCurrentSceneCoveredByUI(true);

    var pauseLower = topFullScreen.Config.PauseLowerView;
    var topSortOrder = topFullScreen.SortOrder;

    foreach (var win in _allWindows)
    {
        if (win == null || win == topFullScreen)
            continue;

        if (win.SortOrder < topSortOrder)
        {
            if (pauseLower)
                win.HideByCover();
            else
                win.ReShowByCover();
        }
        else
        {
            win.ReShowByCover();
        }
    }
}

private static void InsertSorted(List<UIWindow> windows, UIWindow window)
{
    var index = windows.BinarySearch(window, WindowSortOrderComparer.Instance);
    if (index < 0)
        index = ~index;
    windows.Insert(index, window);
}

public int Compare(UIWindow x, UIWindow y)
{
    return x.SortOrder.CompareTo(y.SortOrder);
}

public static UIRuntime Create(
    UIViewConfigTable configTable,
    GameObject uiRootObject,
    Camera uiCamera,
    Transform hiddenRoot,
    GameObject inputBlockObject,
    GameObject maskObject,
    IUIAssetService assetService)
{
    if (configTable == null)
        throw new ArgumentNullException(nameof(configTable));
    if (uiRootObject == null)
        throw new ArgumentNullException(nameof(uiRootObject));
    if (hiddenRoot == null)
        throw new ArgumentNullException(nameof(hiddenRoot));
    if (inputBlockObject == null)
        throw new ArgumentNullException(nameof(inputBlockObject));
    if (maskObject == null)
        throw new ArgumentNullException(nameof(maskObject));
    if (assetService == null)
        throw new ArgumentNullException(nameof(assetService));

    UIViewRegistry.Initialize(configTable);

    var root = new UIRoot(uiRootObject, uiCamera, hiddenRoot);
    RegisterDefaultLayers(root, uiRootObject.transform);

    var mask = new UIMaskService(maskObject);
    var blur = new UIBlurService();
    var inputBlock = new UIInputBlockService(inputBlockObject);

    return new UIRuntime(root, assetService, mask, blur, inputBlock);
}

private static void RegisterDefaultLayers(UIRoot root, Transform rootTransform)
{
    TryRegister(root, rootTransform, UILayer.Scene, "Canvas_Scene");
    TryRegister(root, rootTransform, UILayer.World, "Canvas_World");
    TryRegister(root, rootTransform, UILayer.Hud, "Canvas_Hud");
    TryRegister(root, rootTransform, UILayer.HudTop, "Canvas_Hud_Top");
    TryRegister(root, rootTransform, UILayer.Normal, "Canvas_Normal");
    TryRegister(root, rootTransform, UILayer.Top, "Canvas_Top");
    TryRegister(root, rootTransform, UILayer.Mask, "Canvas_Mask");
    TryRegister(root, rootTransform, UILayer.Guide, "Canvas_Guide");
    TryRegister(root, rootTransform, UILayer.Tip, "Canvas_Tip");
    TryRegister(root, rootTransform, UILayer.Overlay, "Canvas_Overlay");
    TryRegister(root, rootTransform, UILayer.Debug, "Canvas_Debug");
}

private static void TryRegister(UIRoot root, Transform rootTransform, UILayer layer, string path)
{
    var transform = rootTransform.Find(path);
    if (transform != null)
        root.RegisterLayer(layer, transform);
}

public UIInputBlockService(GameObject blockObject)
{
    _blockObject = blockObject ?? throw new ArgumentNullException(nameof(blockObject));
    _blockObject.SetActive(false);
}

public void AddRef(string reason)
{
    reason = string.IsNullOrEmpty(reason) ? "Unknown" : reason;
    _references.TryGetValue(reason, out var count);
    _references[reason] = count + 1;
    _referenceCount++;
    if (_referenceCount == 1 && !_blockObject.activeSelf)
        _blockObject.SetActive(true);
}

public void RemoveRef(string reason)
{
    reason = string.IsNullOrEmpty(reason) ? "Unknown" : reason;
    if (!_references.TryGetValue(reason, out var count))
        return;

    if (count <= 1)
        _references.Remove(reason);
    else
        _references[reason] = count - 1;

    _referenceCount = Math.Max(0, _referenceCount - 1);
    if (_referenceCount == 0 && _blockObject.activeSelf)
        _blockObject.SetActive(false);
}

public void Dispose()
{
    _references.Clear();
    _referenceCount = 0;
    if (_blockObject != null)
        _blockObject.SetActive(false);
}

public UIMaskService(GameObject maskObject)
{
    _maskObject = maskObject ?? throw new ArgumentNullException(nameof(maskObject));
    _image = _maskObject.GetComponent<Image>() ??
        throw new ArgumentException("[UIMaskService] Mask object must contain an Image.", nameof(maskObject));
    _button = _maskObject.GetComponent<Button>() ??
        throw new ArgumentException("[UIMaskService] Mask object must contain a Button.", nameof(maskObject));
    _darkColor = _image.color;
    _button.onClick.AddListener(HandleClick);
    _maskObject.SetActive(false);
}

public void Show(UIWindow window, UIMaskMode mode)
{
    if (window == null || mode == UIMaskMode.None)
        return;

    if (_windows.TryGetValue(window, out var currentMode) && currentMode == mode)
        return;

    _windows[window] = mode;
    Refresh();
}

public void Hide(UIWindow window)
{
    if (window == null)
        return;

    if (!_windows.Remove(window))
        return;

    Refresh();
}

public void Refresh()
{
    _topWindow = null;
    _topMode = UIMaskMode.None;

    foreach (var entry in _windows)
    {
        var window = entry.Key;
        if (window == null ||
            (window.State != UIWindowState.Opening && !window.IsReady) ||
            window.GameObject == null)
            continue;

        if (_topWindow == null || window.SortOrder > _topWindow.SortOrder)
        {
            _topWindow = window;
            _topMode = entry.Value;
        }
    }

    if (_topWindow == null)
    {
        if (_maskObject.activeSelf)
            _maskObject.SetActive(false);
        return;
    }

    var targetTransform = _topWindow.GameObject.transform;
    var parent = targetTransform.parent;
    if (parent == null)
    {
        if (_maskObject.activeSelf)
            _maskObject.SetActive(false);
        return;
    }

    if (!_image.raycastTarget)
        _image.raycastTarget = true;

    var color = _topMode == UIMaskMode.BlockInputOnly
        ? new Color(_darkColor.r, _darkColor.g, _darkColor.b, 0f)
        : _darkColor;
    if (_image.color != color)
        _image.color = color;

    var maskTransform = _maskObject.transform;
    if (maskTransform.parent != parent)
        maskTransform.SetParent(parent, false);
    if (!_maskObject.activeSelf)
        _maskObject.SetActive(true);

    var maskIndex = maskTransform.GetSiblingIndex();
    var targetIndex = targetTransform.GetSiblingIndex();
    if (maskIndex + 1 != targetIndex)
    {
        var desiredIndex = maskIndex < targetIndex ? targetIndex - 1 : targetIndex;
        maskTransform.SetSiblingIndex(desiredIndex);
    }
}

private void HandleClick()
{
    if (_topWindow == null)
        return;

    if (_topMode == UIMaskMode.DarkMaskClose || _topWindow.Config.CloseByMask)
        _topWindow.CloseAsync().Forget();
}

public void Dispose()
{
    _windows.Clear();
    _topWindow = null;
    _button.onClick.RemoveListener(HandleClick);
    if (_maskObject != null && _maskObject.activeSelf)
        _maskObject.SetActive(false);
}

public UIWindow(UIRuntime runtime, Type viewType, UIViewConfig config, int windowIndex)
{
    _runtime = runtime ?? throw new ArgumentNullException(nameof(runtime));
    ViewType = viewType ?? throw new ArgumentNullException(nameof(viewType));
    Config = config ?? throw new ArgumentNullException(nameof(config));
    WindowIndex = windowIndex;
    _openBlockReason = $"Open_{viewType.Name}";
    _sortOrder = (int)config.Layer * 1000000 + config.SortOffset * 10000 + windowIndex;
}

public UniTask OpenAsync(Type viewType, object param)
{
    if (IsOpening)
        return _openTask;

    if (State != UIWindowState.None && !IsCached)
        return UniTask.CompletedTask;

    _openTask = OpenCoreAsync(viewType, param, IsCached).Preserve();
    return _openTask;
}

public async UniTask RefreshAsync(object param)
{
    if (State == UIWindowState.Hidden && !_hiddenForCache)
        ReShowByCover();

    if (State != UIWindowState.Opened || View == null)
        return;

    await View.RefreshInternal(param);
}

public UniTask CloseAsync(object result = null)
{
    if (State == UIWindowState.Closing)
        return _closeTask;

    if (State == UIWindowState.Closed || State == UIWindowState.Disposed || IsCached)
        return UniTask.CompletedTask;

    _closeTask = CloseCoreAsync(result).Preserve();
    return _closeTask;
}

public void HideByCover()
{
    if (State != UIWindowState.Opened)
        return;

    State = UIWindowState.Hiding;
    if (GameObject != null && Config.HideLowerView)
        GameObject.SetActive(false);
    State = UIWindowState.Hidden;
}

public void ReShowByCover()
{
    if (State != UIWindowState.Hidden || _hiddenForCache)
        return;

    if (GameObject != null)
        GameObject.SetActive(true);
    State = UIWindowState.Opened;
}

public bool HandleEsc()
{
    if (!Config.CloseByEsc)
        return true;

    if (View != null && View.EscInternal())
        return true;

    CloseAsync().Forget();
    return true;
}

private async UniTask OpenCoreAsync(Type viewType, object param, bool reuseCachedInstance)
{
    _runtime.InputBlock.AddRef(_openBlockReason);

    try
    {
        if (reuseCachedInstance)
        {
            if (GameObject == null || View == null)
                throw new InvalidOperationException("[UIWindow] Cached window is missing its instance or view.");

            GameObject.SetActive(true);
        }
        else
        {
            State = UIWindowState.Loading;

            var instance = await _runtime.Asset.InstantiateAsync(
                Config.PrefabReference,
                _runtime.Root.HiddenRoot,
                DestroyToken);

            if (IsDisposed)
            {
                _runtime.Asset.Release(instance);
                throw new OperationCanceledException("[UIWindow] Window was disposed while loading.");
            }

            GameObject = instance ??
                throw new InvalidOperationException($"[UIWindow] Instantiated object is null: {Config.PrefabReference.AssetGUID}");
            GameObject.transform.SetParent(_runtime.Root.HiddenRoot, false);

            View = CreateViewModule(viewType, GameObject);
            await View.StartAsync();
        }

        ThrowIfDisposed();
        State = UIWindowState.Opening;

        await View.OpenInternal(param);
        ThrowIfDisposed();

        if (!_featureModulesCreated)
            await CreateWindowFeatureModulesAsync();

        AttachToLayer();
        View.AdaptRootTransform();
        RenderOrder = _sortOrder;
        ApplyRenderOrder();
        await PrepareWindowFeatureModulesBeforeShow();
        ThrowIfDisposed();

        await View.PlayOpenAnimationInternal();
        ThrowIfDisposed();

        _hiddenForCache = false;
        State = UIWindowState.Opened;
        View.ShownInternal();
        _runtime.RefreshPresentation();
    }
    catch
    {
        if (!IsDisposed)
            Dispose();

        _runtime.RemoveWindow(this);
        _runtime.RefreshPresentation();
        throw;
    }
    finally
    {
        _openTask = default;
        _runtime.InputBlock.RemoveRef(_openBlockReason);
    }
}

private async UniTask CloseCoreAsync(object result)
{
    if (State == UIWindowState.None || IsOpening)
    {
        Dispose();
        _runtime.RemoveWindow(this);
        _runtime.RefreshPresentation();
        _closeTask = default;
        return;
    }

    State = UIWindowState.Closing;
    _runtime.Mask.Hide(this);
    _runtime.Blur.Detach(this);

    if (View != null)
    {
        await View.PlayCloseAnimationInternal();
        await View.CloseInternal(result);
    }

    if (IsDisposed)
    {
        _closeTask = default;
        return;
    }

    if (Config.CacheMode == UICacheMode.HideOnClose ||
        Config.CacheMode == UICacheMode.Preload)
    {
        HideForCache();
    }
    else
    {
        State = UIWindowState.Closed;
        Dispose();
        _runtime.RemoveWindow(this);
    }

    _closeTask = default;
    _runtime.RefreshPresentation();
}

private ViewBase CreateViewModule(Type viewType, GameObject gameObject)
{
    var bind = gameObject.GetComponent<CSharpUIBindBehaviour>();
    var binder = bind != null ? UIViewBinderFactory.Create(viewType, bind) : null;
    var view = (ViewBase)Activator.CreateInstance(viewType);

    view.BindView(this, gameObject, binder);
    RegisterChild(view);
    return view;
}

private async UniTask CreateWindowFeatureModulesAsync()
{
    if (Config.MaskMode != UIMaskMode.None)
    {
        var module = await AddModuleAsync(new UIMaskWindowModule());
        _maskOpenBlocker = module;
    }

    if (Config.BlurMode != UIBlurMode.None)
    {
        var module = await AddModuleAsync(new UIBlurWindowModule());
        _blurOpenBlocker = module;
    }

    _featureModulesCreated = true;
}

private async UniTask PrepareWindowFeatureModulesBeforeShow()
{
    if (_maskOpenBlocker != null)
        await _maskOpenBlocker.PrepareBeforeShow();
    if (_blurOpenBlocker != null)
        await _blurOpenBlocker.PrepareBeforeShow();
}

private void AttachToLayer()
{
    var parent = _runtime.Root.GetLayerRoot(Config.Layer);
    GameObject.transform.SetParent(parent, false);
    GameObject.transform.SetAsLastSibling();
}

private void ApplyRenderOrder()
{
    if (_renderOrder == -1 || GameObject == null)
        return;

    var canvas = GameObject.GetComponent<Canvas>();
    if (canvas == null)
        return;

    canvas.overrideSorting = true;
    canvas.sortingOrder = _renderOrder;

    var dynRenders = GameObject.GetComponentsInChildren<DynCanvaRenderOrder>(true);
    foreach (var render in dynRenders)
    {
        render.SetRenderOrder(canvas.sortingLayerID, _renderOrder);
    }
}

private void HideForCache()
{
    if (GameObject == null)
        return;

    GameObject.SetActive(false);
    GameObject.transform.SetParent(_runtime.Root.HiddenRoot, false);
    _hiddenForCache = true;
    State = UIWindowState.Hidden;
}

private void ThrowIfDisposed()
{
    if (IsDisposed)
        throw new OperationCanceledException("[UIWindow] Window has been disposed.");

    DestroyToken.ThrowIfCancellationRequested();
}

protected override void OnStop()
{
    _maskOpenBlocker = null;
    _blurOpenBlocker = null;

    State = UIWindowState.Disposed;
    _runtime.Mask.Hide(this);
    _runtime.Blur.Detach(this);

    if (GameObject != null)
    {
        _runtime.Asset.Release(GameObject);
        GameObject = null;
    }
}

