public static string FormatFileSize(int size)
{
    if (size > 1024 * 1024)
    {
        return ZString.Format("{0:0.##} MB", 1.0f * size / 1024 / 1024);
    }
    else if (size > 1024)
    {
        return ZString.Format("{0:0.##} KB", 1.0f * size / 1024);
