private static void onLogMessageReceived(string condition, string stacktrace, LogType type)
{
    switch (type)
    {
        case LogType.Error:
        {
            using (var sb = ZString.CreateStringBuilder())
            {
                sb.Append(condition);
                sb.Append("\r\n");
                sb.Append(stacktrace);
                string message = sb.ToString();
                log.Error(message);
                RecordException("Error", message);
            }

            break;
        }
        case LogType.Assert:
        {
            using (var sb = ZString.CreateStringBuilder())
            {
                sb.Append(condition);
                sb.Append("\r\n");
                sb.Append(stacktrace);
                string message = sb.ToString();
                log.Error(message);
                RecordException("Assert", message);
            }

            break;
        }
        case LogType.Exception:
        {
            using (var sb = ZString.CreateStringBuilder())
            {
                sb.Append(condition);
                sb.Append("\r\n");
                sb.Append(stacktrace);
                string message = sb.ToString();
                log.Error(message);
                RecordException("Exception", message);
            }

            break;
        }
        case LogType.Warning:
        {
            using (var sb = ZString.CreateStringBuilder())
            {
                sb.Append(condition);
                sb.Append("\r\n");
                sb.Append(stacktrace);
                string message = sb.ToString();
                log.Warn(message);
            }

            break;
        }
        default:
        {
            using (var sb = ZString.CreateStringBuilder())
            {
                sb.Append(condition);
                sb.Append("\r\n");
                sb.Append(stacktrace);
                string message = sb.ToString();
                log.Debug(message);
            }

            break;
        }
    }
}

