public ObjectPool(int capacity = 16)
{
    _capacity = capacity;
    _items = new ConcurrentBag<T>();
}

        public T Get()
        {
            var item = _fastItem;
            if (item == null || Interlocked.CompareExchange(ref _fastItem, null, item) != item)
            {
                if (_items.TryTake(out item))
                {
                    Interlocked.Decrement(ref _count);
                }
                else
                {
                    if (CreateAction != null)
                    {
                        item = CreateAction();
                    }
                    else
                    {
                        item = new T();
                    }
                }
            }
#if DEBUG
            lock(lockObject){
                _cache.Remove(item, out int value);
            }
#endif

            return item;
        }

public void Return(T obj)
{
#if DEBUG
    lock(lockObject){
        if(!_cache.TryAdd(obj,1)){
            throw new Exception("ObjectPool Repeat return obj");
        }
    }
#endif
    if (_fastItem != null || Interlocked.CompareExchange(ref _fastItem, obj, null) != null)
    {
        if (Interlocked.Increment(ref _count) <= _capacity)
        {
            _items.Add(obj);

            if (ResetAction != null)
            {
                ResetAction(obj);
            }

            return;
        }
        Interlocked.Decrement(ref _count);
    }
    else
    {
        // If _fastItem is null and not set, directly call ResetAction
        if (ResetAction != null)
        {
            ResetAction(obj);
        }
    }
}


public void Clear()
{
#if DEBUG
    _cache.Clear();
#endif
    if (DisposeAction != null)
    {
        for (int i = 0; i < _count; i++)
        {
            if (_items.TryTake(out var item))
            {
                DisposeAction(item);
            }
        }
    }
    _items.Clear();
}

public AutoReturnPoolObject(ObjectPool<T> pool)
{
    _pool = pool;
    _obj = _pool.Get();
}


public void Dispose()
{
    _pool.Return(_obj);
}
